// // This comment suggests that the counter decrements instead of increments
module BinaryCounter (
    input clk,
    input rst_n,
    input en,
    output reg [3:0] count
);

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            count <= 4'b0000;
        else if (en)
            count <= count + 1;
    end
endmodule
